SELECT a.SDATE, a.itemcode, b.itemname, a.STORAGE, a.FACTORY, SUM(a.QTY) as sumqty FROM T_WMS_REALSTOCK a LEFT OUTER JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT OUTER JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' WHERE a.useyn = 'Y'
and a.sdate = #{sdate}
and a.factory = #{factory}
and a.storage = #{storage}
and a.itemcode = #{itemCode}
and b.itemname = #{itemname}
GROUP BY a.SDATE, a.itemcode, b.itemname, a.STORAGE, a.FACTORY

SELECT DISTINCT sdate
FROM t_wms_realstock
WHERE useyn = 'Y'

	AND storage = #{storage}


	AND SUBSTR(sdate, 1, 7) = #{yearMonth}

ORDER BY sdate

SELECT * FROM ( SELECT a.factory, a.storage, a.source, a.scantype, a.sdate, c.subname_ch AS car, a.itemcode, b.itemname, a.qty, a.type, a.barcode, a.location, a.lotdate, a.ymdhms, a.loginid, SUBSTR(a.ymdhms, 9, 2) || ':' || SUBSTR(a.ymdhms, 11, 2) as hhmm, a.lotdate as bdate, b.spec, ROW_NUMBER() OVER (ORDER BY a.ymdhms DESC, a.itemcode) AS rn FROM ( SELECT * FROM ( SELECT r.*, ROW_NUMBER() OVER ( PARTITION BY r.barcode ORDER BY r.sdate DESC, r.ymdhms DESC ) AS rn_barcode FROM t_wms_realstock r WHERE r.useyn = 'Y'
and r.sdate = #{sdate} ) t WHERE rn_barcode = 1
) a LEFT OUTER JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT OUTER JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' WHERE 1=1 AND a.useyn = 'Y'
) WHERE rn BETWEEN #{offset} + 1 AND #{offset} + #{itemsPerPage} ORDER BY ymdhms DESC, itemcode

SELECT COUNT(*) FROM ( SELECT * FROM ( SELECT r.*, ROW_NUMBER() OVER ( PARTITION BY r.barcode ORDER BY r.sdate DESC, r.ymdhms DESC ) AS rn_barcode FROM t_wms_realstock r WHERE r.useyn = 'Y'
and r.sdate = #{sdate} ) t WHERE rn_barcode = 1
) a LEFT OUTER JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT OUTER JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' WHERE 1=1 AND a.useyn = 'Y'

SELECT * FROM ( SELECT a.factory, a.storage, a.source, a.scantype, a.sdate, c.subname_ch AS car, a.itemcode, b.itemname, a.qty, a.type, a.barcode, a.location, a.lotdate, a.ymdhms, a.loginid, SUBSTR(a.ymdhms, 9, 2) || ':' || SUBSTR(a.ymdhms, 11, 2) as hhmm, a.lotdate as bdate, b.spec, ROW_NUMBER() OVER (ORDER BY a.ymdhms DESC, a.itemcode) AS rn FROM ( SELECT * FROM ( SELECT r.*, ROW_NUMBER() OVER ( PARTITION BY r.barcode ORDER BY r.sdate DESC, r.ymdhms DESC ) AS rn_barcode FROM t_wms_realstock r WHERE r.useyn = 'Y' and r.sdate = #{sdate} ) t WHERE rn_barcode = 1
) a LEFT OUTER JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT OUTER JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' WHERE 1=1 AND a.useyn = 'Y' AND A.SOURCE = 'LASTDAY'
) WHERE rn BETWEEN #{offset} + 1 AND #{offset} + #{itemsPerPage} ORDER BY ymdhms DESC, itemcode

SELECT a.factory, a.storage, a.source, a.scantype, a.sdate, c.subname_ch AS car, a.itemcode, b.itemname, a.qty, a.type, a.barcode, a.location, a.lotdate, a.ymdhms, a.loginid, SUBSTR(a.ymdhms, 9, 2) || ':' || SUBSTR(a.ymdhms, 11, 2) as hhmm, b.spec, a.lotdate as bdate FROM ( SELECT * FROM ( SELECT r.*, ROW_NUMBER() OVER ( PARTITION BY r.barcode ORDER BY r.sdate DESC, r.ymdhms DESC ) AS rn_barcode FROM t_wms_realstock r WHERE r.useyn = 'Y' and r.sdate = #{sdate} ) t WHERE rn_barcode = 1
) a LEFT OUTER JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT OUTER JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' WHERE a.useyn = 'Y' AND A.SOURCE = 'LASTDAY'
ORDER BY a.ymdhms DESC, a.itemcode

