mapper.select:
SELECT T.*,
/* MODULE */ --C.SUBNAME_CH AS RACKID, RACK AS RACKID, CEIL(RN / 8) AS MODULENUM,
/* LEVEL */ CASE FLOOR(MOD(RN - 1, 8) / 2) WHEN 0 THEN 'A' WHEN 1 THEN 'B' WHEN 2 THEN 'C' WHEN 3 THEN 'D' END AS LEVELNAME,
/* POSITION */ MOD(RN - 1, 2) + 1 AS POSITIONNUM,
/* 최종 LOCATION 문자열 */ AREA || '-' || STORAGE || '-' || C.SUBNAME_CH || '-' || CEIL(RN / 8) || '-' || CASE FLOOR(MOD(RN - 1, 8) / 2) WHEN 0 THEN 'A' WHEN 1 THEN 'B' WHEN 2 THEN 'C' WHEN 3 THEN 'D' END || '-' || (MOD(RN - 1, 2) + 1) AS LOCATION, 'occupied' AS POSITIONSTATUS
FROM ( SELECT L.IID,L.SDATE,L.USEYN,L.YMDHMS,L.BARCODE,L.ITEMCODE,L.QTY,L.MEMO,L.LOGINID,L.FACTORY AS AREA,L.STORAGE,L.SOURCE,L.OKYN,L.RACK, ROW_NUMBER() OVER (ORDER BY YMDHMS) AS RN FROM t_wms_location L INNER JOIN T_MI_ITEM B ON L.ITEMCODE = B.ITEMCODE INNER JOIN t_mi_typesub C ON B.carno = C.subcode AND C.typecode = 'MI041' WHERE UPPER(C.SUBNAME_CH) = #{rackId} AND UPPER(STORAGE) = UPPER(#{storage}) AND UPPER(L.FACTORY) = #{factory} AND USEYN = 'Y' ) T INNER JOIN T_MI_ITEM B ON T.ITEMCODE = B.ITEMCODE INNER JOIN t_mi_typesub C ON B.carno = C.subcode AND C.typecode = 'MI041' ORDER BY RN

