SELECT * FROM ( SELECT ROWNUM AS rn, sub.* FROM ( WITH /* ITEMCODE별 최신 BUY CUSTCODE (대체용) */ buycust_latest AS ( SELECT itemcode, custcode FROM ( SELECT itemcode, custcode, ROW_NUMBER() OVER (PARTITION BY itemcode ORDER BY condate DESC) AS rn FROM t_mi_price_buycust ) WHERE rn = 1 ),
/* ITEMCODE별 대표 거래처(GMAIN=1) */ item_custinfo_main AS ( SELECT itemcode, custcode FROM ( SELECT itemcode, custcode, ROW_NUMBER() OVER ( PARTITION BY itemcode ORDER BY CASE WHEN custcode = '0001' THEN 1 ELSE 2 END, custcode ) AS rn FROM t_mi_item_custinfo WHERE gmain = 1 ) WHERE rn = 1 )
SELECT a.iid, a.indate, a.loginid, a.factory, a.storage,
/* ✅ 최종 거래처코드(표시/검색 기준 통일) */ COALESCE(a.custcode, d.custcode, bl.custcode) AS custcode,
/* ✅ 최종 거래처명 */ cc.cu_sangho AS cname,
c.subname_ch AS car, a.itemcode, b.itemname, a.qty, a.barcode, a.invoiceno, a.intf_yn AS intf_yn, a.mes_key AS meskey, a.ymdhms, SUBSTR(a.ymdhms, 9, 2) || ':' || SUBSTR(a.ymdhms, 11, 2) AS hhmm, a.bdate
FROM t_wms_inbound a LEFT JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041'
/* ✅ 대표거래처(d) */ LEFT JOIN item_custinfo_main d ON a.itemcode = d.itemcode
/* ✅ 최신 매입 거래처(bl) */ LEFT JOIN buycust_latest bl ON a.itemcode = bl.itemcode
/* ✅ 최종 거래처코드로 거래처명 조인 */ LEFT JOIN c_cust cc ON cc.cu_code = COALESCE(a.custcode, d.custcode, bl.custcode)
WHERE
a.useyn = 'Y'
a.useyn = 'N'
AND a.source IN ('INCOMINGLOCAL', 'INCOMINGCKD')
ORDER BY a.indate DESC, a.ymdhms DESC, a.itemcode, a.barcode, a.loginid ) sub WHERE ROWNUM <= #{offset} + #{itemsPerPage} ) WHERE rn > #{offset}

WITH /* ITEMCODE별 최신 BUY CUSTCODE (대체용) */ buycust_latest AS ( SELECT itemcode, custcode FROM ( SELECT itemcode, custcode, ROW_NUMBER() OVER (PARTITION BY itemcode ORDER BY condate DESC) AS rn FROM t_mi_price_buycust ) WHERE rn = 1 ),
/* ITEMCODE별 대표 거래처(GMAIN=1) */ item_custinfo_main AS ( SELECT itemcode, custcode FROM ( SELECT itemcode, custcode, ROW_NUMBER() OVER ( PARTITION BY itemcode ORDER BY CASE WHEN custcode = '0001' THEN 1 ELSE 2 END, custcode ) AS rn FROM t_mi_item_custinfo WHERE gmain = 1 ) WHERE rn = 1 )
SELECT a.indate, a.loginid, a.factory, a.storage,
/* ✅ 최종 거래처코드(표시/검색 기준 통일) */ COALESCE(a.custcode, d.custcode, bl.custcode) AS custcode,
/* ✅ 최종 거래처명 */ cc.cu_sangho AS cname,
c.subname_ch AS car, a.itemcode, b.itemname, a.qty, a.barcode, a.invoiceno, a.intf_yn AS intf_yn, a.mes_key AS meskey, a.ymdhms, SUBSTR(a.ymdhms, 9, 2) || ':' || SUBSTR(a.ymdhms, 11, 2) AS hhmm, a.bdate
FROM t_wms_inbound a LEFT JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041'
/* ✅ 대표거래처(d) */ LEFT JOIN item_custinfo_main d ON a.itemcode = d.itemcode
/* ✅ 최신 매입 거래처(bl) */ LEFT JOIN buycust_latest bl ON a.itemcode = bl.itemcode
/* ✅ 최종 거래처코드로 거래처명 조인 */ LEFT JOIN c_cust cc ON cc.cu_code = COALESCE(a.custcode, d.custcode, bl.custcode)
WHERE
a.useyn = 'Y'
a.useyn = 'N'
AND a.source IN ('INCOMINGLOCAL', 'INCOMINGCKD')
ORDER BY a.indate DESC, a.ymdhms DESC, a.itemcode, a.barcode, a.loginid

SELECT * FROM ( SELECT ROWNUM AS rn, sub.* FROM ( WITH /* ITEMCODE별 최신 BUY CUSTCODE (대체용) */ buycust_latest AS ( SELECT itemcode, custcode FROM ( SELECT itemcode, custcode, ROW_NUMBER() OVER (PARTITION BY itemcode ORDER BY condate DESC) AS rn FROM t_mi_price_buycust ) WHERE rn = 1 ),
/* ITEMCODE별 대표 거래처(GMAIN=1) */ item_custinfo_main AS ( SELECT itemcode, custcode FROM ( SELECT itemcode, custcode, ROW_NUMBER() OVER ( PARTITION BY itemcode ORDER BY CASE WHEN custcode = '0001' THEN 1 ELSE 2 END, custcode ) AS rn FROM t_mi_item_custinfo WHERE gmain = 1 ) WHERE rn = 1 )
SELECT a.indate, a.factory, a.storage,
/* ✅ 최종 거래처코드(표시/검색/그룹 통일) */ COALESCE(a.custcode, d.custcode, bl.custcode) AS custcode,
/* ✅ 최종 거래처명 */ cc.cu_sangho AS cname,
c.subname_ch AS car, a.itemcode, b.itemname, b.spec, SUM(a.qty) AS qty, a.mes_key AS ifno, a.invoiceno, a.intf_yn AS intf_yn
FROM t_wms_inbound a LEFT JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041'
/* ✅ 대표거래처(d) */ LEFT JOIN item_custinfo_main d ON a.itemcode = d.itemcode
/* ✅ 최신 매입 거래처(bl) */ LEFT JOIN buycust_latest bl ON a.itemcode = bl.itemcode
/* ✅ 최종 거래처코드로 거래처명 조인 */ LEFT JOIN c_cust cc ON cc.cu_code = COALESCE(a.custcode, d.custcode, bl.custcode)
WHERE a.useyn = 'Y' AND a.source IN ('INCOMINGCKD','INCOMINGLOCAL')
/* ✅ GROUP BY도 “최종 거래처” 기준으로 */ GROUP BY a.indate, a.factory, a.storage, COALESCE(a.custcode, d.custcode, bl.custcode), cc.cu_sangho, c.subname_ch, a.itemcode, b.itemname, b.spec, a.invoiceno, a.intf_yn, a.mes_key
ORDER BY a.indate DESC, a.itemcode ) sub WHERE ROWNUM <= #{offset} + #{itemsPerPage} ) WHERE rn > #{offset}

SELECT * FROM ( SELECT ROWNUM AS rn, sub.* FROM ( SELECT a.indate, a.factory, a.storage, c.subname_ch AS car, a.itemcode, b.itemname, SUM(a.qty) AS qty, a.intf_yn, a.wccode FROM t_wms_workmove a LEFT JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' WHERE a.useyn = 'Y' and source = 'WIPINPUT'
GROUP BY a.indate, a.factory, a.storage, c.subname_ch, a.itemcode, b.itemname, a.intf_yn, a.wccode ORDER BY indate DESC, itemcode, a.intf_yn ) sub WHERE ROWNUM <= #{offset} + #{itemsPerPage}
) WHERE rn > #{offset}

