mapper.select:
SELECT COUNT(*) 
FROM T_MI_PRICE_BUYCUST 
WHERE ITEMCODE = #{itemcode} 
AND CONDATE = (
    SELECT MAX(CONDATE)
    FROM T_MI_PRICE_BUYCUST 
    WHERE ITEMCODE = #{itemcode} 
)
AND (UNITPRICE = 0 OR UNITPRICE IS NULL)

SELECT * FROM ( SELECT t.*, ROW_NUMBER() OVER (ORDER BY t.itemcode) AS rn,
/* 전체 개수 */ (SELECT COUNT(DISTINCT inner_t.barcode) FROM ( WITH ever_send AS ( SELECT DISTINCT barcode FROM t_wms_factorymove WHERE useyn='Y' AND source='SENDING' ), last_evt AS ( SELECT barcode, MAX(sdate) AS last_sdate FROM t_wms_factorymove WHERE useyn='Y' GROUP BY barcode ), last_src AS ( SELECT f.barcode, MAX(CASE WHEN f.sdate = l.last_sdate THEN f.source END) AS last_source FROM t_wms_factorymove f JOIN last_evt l ON l.barcode = f.barcode WHERE f.useyn='Y' GROUP BY f.barcode ) SELECT a.barcode FROM t_wms_factorymove a LEFT JOIN t_mi_item b ON b.itemcode = a.itemcode LEFT JOIN t_mi_typesub c ON c.subcode = b.carno AND c.typecode = 'MI041' LEFT JOIN ever_send es ON es.barcode = a.barcode LEFT JOIN last_src ls ON ls.barcode = a.barcode WHERE a.useyn = 'Y'
GROUP BY a.itemcode, b.itemname, c.subname_ch, a.barcode ) inner_t ) AS TOTALCOUNT,
/* 총 수량 */ (SELECT NVL(SUM(inner_t.total_qty), 0) FROM ( WITH ever_send AS ( SELECT DISTINCT barcode FROM t_wms_factorymove WHERE useyn='Y' AND source='SENDING' ), last_evt AS ( SELECT barcode, MAX(sdate) AS last_sdate FROM t_wms_factorymove WHERE useyn='Y' GROUP BY barcode ), last_src AS ( SELECT f.barcode, MAX(CASE WHEN f.sdate = l.last_sdate THEN f.source END) AS last_source FROM t_wms_factorymove f JOIN last_evt l ON l.barcode = f.barcode WHERE f.useyn='Y' GROUP BY f.barcode ) SELECT SUM(CASE WHEN source = 'SENDING' THEN qty END) + SUM(CASE WHEN source = 'RECEIVING' THEN qty END) AS total_qty FROM t_wms_factorymove a LEFT JOIN t_mi_item b ON b.itemcode = a.itemcode LEFT JOIN t_mi_typesub c ON c.subcode = b.carno AND c.typecode = 'MI041' LEFT JOIN ever_send es ON es.barcode = a.barcode LEFT JOIN last_src ls ON ls.barcode = a.barcode WHERE a.useyn = 'Y'
GROUP BY a.itemcode, b.itemname, c.subname_ch, a.barcode ) inner_t ) AS TOTALQTY
FROM ( WITH ever_send AS ( SELECT DISTINCT barcode FROM t_wms_factorymove WHERE useyn='Y' AND source='SENDING' ), last_evt AS ( SELECT barcode, MAX(sdate) AS last_sdate FROM t_wms_factorymove WHERE useyn='Y' GROUP BY barcode ), last_src AS ( SELECT f.barcode, MAX(CASE WHEN f.sdate = l.last_sdate THEN f.source END) AS last_source FROM t_wms_factorymove f JOIN last_evt l ON l.barcode = f.barcode WHERE f.useyn='Y' GROUP BY f.barcode ) SELECT MAX(CASE WHEN source = 'SENDING' THEN sdate END) AS FROMDATE, MAX(CASE WHEN source = 'RECEIVING' THEN sdate END) AS TODATE, c.SUBNAME_CH as car, a.itemcode, b.itemname, a.barcode, SUM(CASE WHEN source = 'SENDING' THEN qty END) AS FROMQTY, SUM(CASE WHEN source = 'RECEIVING' THEN qty END) AS TOQTY, MAX(CASE WHEN source = 'SENDING' THEN factory END) AS FROMFACTORY, MAX(CASE WHEN source = 'SENDING' THEN storage END) AS FROMSTORAGE, MAX(CASE WHEN source = 'RECEIVING' THEN factory END) AS TOFACTORY, MAX(CASE WHEN source = 'RECEIVING' THEN storage END) AS TOSTORAGE, CASE WHEN SUM(CASE WHEN a.source='RECEIVING' THEN 1 END) = 0 THEN NULL WHEN MAX(CASE WHEN a.source='RECEIVING' AND es.barcode IS NOT NULL AND ls.last_source = 'RECEIVING' THEN 1 ELSE 0 END) = 1 THEN 'O' ELSE 'X' END AS COMPLETE FROM t_wms_factorymove a LEFT JOIN t_mi_item b ON b.itemcode = a.itemcode LEFT JOIN t_mi_typesub c ON c.subcode = b.carno AND c.typecode = 'MI041' LEFT JOIN ever_send es ON es.barcode = a.barcode LEFT JOIN last_src ls ON ls.barcode = a.barcode WHERE a.useyn = 'Y'
GROUP BY a.itemcode, b.itemname, c.subname_ch, a.barcode ) t ) where complete = 'X'
and rn BETWEEN #{offset} + 1 AND #{offset} + #{limit}
ORDER BY rn

SELECT * FROM ( SELECT tg.FROMDATE, tg.TODATE, tg.CAR, tg.ITEMCODE, tg.ITEMNAME, tg.FROMQTY, tg.TOQTY, tg.FROMFACTORY, tg.FROMSTORAGE, tg.TOFACTORY, tg.TOSTORAGE, ROW_NUMBER() OVER (ORDER BY tg.ITEMCODE) AS rn,
/* 전체 개수 */ ( SELECT COUNT(DISTINCT inner_t.barcode) FROM ( WITH ever_send AS ( SELECT DISTINCT barcode FROM t_wms_factorymove WHERE useyn = 'Y' AND source = 'SENDING' ), last_evt AS ( SELECT barcode, MAX(sdate) AS last_sdate FROM t_wms_factorymove WHERE useyn = 'Y' GROUP BY barcode ), last_src AS ( SELECT f.barcode, MAX( CASE WHEN f.sdate = l.last_sdate THEN f.source END ) AS last_source FROM t_wms_factorymove f JOIN last_evt l ON l.barcode = f.barcode WHERE f.useyn = 'Y' GROUP BY f.barcode ) SELECT a.barcode FROM t_wms_factorymove a LEFT JOIN t_mi_item b ON b.itemcode = a.itemcode LEFT JOIN t_mi_typesub c ON c.subcode = b.carno AND c.typecode = 'MI041' LEFT JOIN ever_send es ON es.barcode = a.barcode LEFT JOIN last_src ls ON ls.barcode = a.barcode WHERE a.useyn = 'Y'
GROUP BY a.itemcode, b.itemname, c.subname_ch, a.barcode ) inner_t ) AS TOTALCOUNT,
/* 총 수량 */ ( SELECT NVL(SUM(inner_t.total_qty), 0) FROM ( WITH ever_send AS ( SELECT DISTINCT barcode FROM t_wms_factorymove WHERE useyn = 'Y' AND source = 'SENDING' ), last_evt AS ( SELECT barcode, MAX(sdate) AS last_sdate FROM t_wms_factorymove WHERE useyn = 'Y' GROUP BY barcode ), last_src AS ( SELECT f.barcode, MAX( CASE WHEN f.sdate = l.last_sdate THEN f.source END ) AS last_source FROM t_wms_factorymove f JOIN last_evt l ON l.barcode = f.barcode WHERE f.useyn = 'Y' GROUP BY f.barcode ) SELECT SUM( CASE WHEN source = 'SENDING' THEN qty END ) + SUM( CASE WHEN source = 'RECEIVING' THEN qty END ) AS total_qty FROM t_wms_factorymove a LEFT JOIN t_mi_item b ON b.itemcode = a.itemcode LEFT JOIN t_mi_typesub c ON c.subcode = b.carno AND c.typecode = 'MI041' LEFT JOIN ever_send es ON es.barcode = a.barcode LEFT JOIN last_src ls ON ls.barcode = a.barcode WHERE a.useyn = 'Y'
GROUP BY a.itemcode, b.itemname, c.subname_ch, a.barcode ) inner_t ) AS TOTALQTY
FROM ( /* ---------------------------------------------------- * 1차: BARCODE 단위로 COMPLETE 상태까지 계산 * ---------------------------------------------------- */ WITH ever_send AS ( SELECT DISTINCT barcode FROM t_wms_factorymove WHERE useyn = 'Y' AND source = 'SENDING' ), last_evt AS ( SELECT barcode, MAX(sdate) AS last_sdate FROM t_wms_factorymove WHERE useyn = 'Y' GROUP BY barcode ), last_src AS ( SELECT f.barcode, MAX( CASE WHEN f.sdate = l.last_sdate THEN f.source END ) AS last_source FROM t_wms_factorymove f JOIN last_evt l ON l.barcode = f.barcode WHERE f.useyn = 'Y' GROUP BY f.barcode ) SELECT base.FROMDATE, base.TODATE, base.CAR, base.ITEMCODE, base.ITEMNAME, SUM(base.FROMQTY) AS FROMQTY, SUM(base.TOQTY) AS TOQTY, base.FROMFACTORY, base.FROMSTORAGE, base.TOFACTORY, base.TOSTORAGE FROM ( SELECT MAX( CASE WHEN source = 'SENDING' THEN sdate END ) AS FROMDATE, MAX( CASE WHEN source = 'RECEIVING' THEN sdate END ) AS TODATE, c.SUBNAME_CH AS CAR, a.itemcode, b.itemname, a.barcode, SUM( CASE WHEN source = 'SENDING' THEN qty END ) AS FROMQTY, SUM( CASE WHEN source = 'RECEIVING' THEN qty END ) AS TOQTY, MAX( CASE WHEN source = 'SENDING' THEN factory END ) AS FROMFACTORY, MAX( CASE WHEN source = 'SENDING' THEN storage END ) AS FROMSTORAGE, MAX( CASE WHEN source = 'RECEIVING' THEN factory END ) AS TOFACTORY, MAX( CASE WHEN source = 'RECEIVING' THEN storage END ) AS TOSTORAGE, CASE WHEN SUM( CASE WHEN a.source = 'RECEIVING' THEN 1 END ) = 0 THEN NULL WHEN MAX( CASE WHEN a.source = 'RECEIVING' AND es.barcode IS NOT NULL AND ls.last_source = 'RECEIVING' THEN 1 ELSE 0 END ) = 1 THEN 'O' ELSE 'X' END AS COMPLETE FROM t_wms_factorymove a LEFT JOIN t_mi_item b ON b.itemcode = a.itemcode LEFT JOIN t_mi_typesub c ON c.subcode = b.carno AND c.typecode = 'MI041' LEFT JOIN ever_send es ON es.barcode = a.barcode LEFT JOIN last_src ls ON ls.barcode = a.barcode WHERE a.useyn = 'Y'
GROUP BY a.itemcode, b.itemname, c.subname_ch, a.barcode ) base /* ---------------------------------------------------- * 2차: COMPLETE = 'O' 만 남기고 * fromdate ~ tostorage 기준으로 다시 GROUP BY * ---------------------------------------------------- */ WHERE base.COMPLETE = 'O' GROUP BY base.FROMDATE, base.TODATE, base.CAR, base.ITEMCODE, base.ITEMNAME, base.FROMFACTORY, base.FROMSTORAGE, base.TOFACTORY, base.TOSTORAGE ) tg ) WHERE 1 = 1
AND rn BETWEEN #{offset} + 1 AND #{offset} + #{limit}
ORDER BY rn

SELECT e.subname_ch AS ITEMTYPE, b.subname_ch AS CAR, a.itemcode AS ITEMCODE, a.itemname AS ITEMNAME, c.subname_ch AS SPEC, a.oitemcode AS OITEMCODE, a.oitemname AS OITEMNAME, a.spec AS SPEC2, d.subname AS LABELCOLOR,
/* 전체 개수 - 모든 행에 반복 */ (SELECT COUNT(*) FROM t_mi_item a2 LEFT OUTER JOIN t_mi_typesub b2 ON a2.carno = b2.subcode AND b2.typecode = 'MI041' LEFT OUTER JOIN t_mi_typesub c2 ON a2.specno = c2.subcode AND c2.typecode = 'MI042' LEFT OUTER JOIN t_mi_typesub d2 ON a2.LABEL_COLOR = d2.subcode AND d2.typecode = 'MI046' LEFT OUTER JOIN t_mi_typesub e2 ON a2.cmb_itemtype = e2.subcode AND e2.typecode = 'MI002' WHERE a2.deldate = ' ' AND e2.subname IS NOT NULL
) AS TOTALCOUNT
FROM t_mi_item a LEFT OUTER JOIN t_mi_typesub b ON a.carno = b.subcode AND b.typecode = 'MI041' LEFT OUTER JOIN t_mi_typesub c ON a.specno = c.subcode AND c.typecode = 'MI042' LEFT OUTER JOIN t_mi_typesub d ON a.LABEL_COLOR = d.subcode AND d.typecode = 'MI046' LEFT OUTER JOIN t_mi_typesub e ON a.cmb_itemtype = e.subcode AND e.typecode = 'MI002' WHERE a.deldate = ' ' AND e.subname IS NOT NULL
ORDER BY e.subname, b.subname, c.subname, a.itemcode, a.itemname
OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

SELECT a.sdate AS SDATE, a.loginid AS LOGINID, a.factory AS FACTORY, a.storage AS STORAGE, a.custcode AS custcode, a.custname AS custname, c.subname_ch AS CAR, a.itemcode AS ITEMCODE, a.oitemcode AS OITEMCODE, b.itemname AS ITEMNAME, a.qty AS QTY, a.barcode AS BARCODE, a.invoiceno AS INVOICENO, a.intf_yn AS INTF_YN, a.mes_key AS MESKEY, a.ymdhms AS YMDHMS, SUBSTR(a.ymdhms, 9, 2) || ':' || SUBSTR(a.ymdhms, 11, 2) AS HHMM, a.bdate AS BDATE, a.iid AS IID,
/* 전체 개수 - 모든 행에 반복 */ (SELECT COUNT(*) FROM t_wms_inbound a2 LEFT JOIN t_mi_item b2 ON a2.itemcode = b2.itemcode LEFT JOIN t_mi_typesub c2 ON b2.carno = c2.subcode AND c2.typecode = 'MI041'
WHERE 1=1 AND a2.source = 'INCOMING'
) AS TOTALCOUNT,
/* 총 수량 - 모든 행에 반복 */ (SELECT NVL(SUM(a2.qty), 0) FROM t_wms_inbound a2 LEFT JOIN t_mi_item b2 ON a2.itemcode = b2.itemcode LEFT JOIN t_mi_typesub c2 ON b2.carno = c2.subcode AND c2.typecode = 'MI041'
WHERE 1=1 AND a2.source = 'INCOMING'
) AS TOTALQTY
FROM t_wms_inbound a LEFT JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041'
WHERE 1=1 AND a.source = 'INCOMING'
ORDER BY a.sdate DESC, a.ymdhms DESC, a.itemcode, a.barcode, a.loginid
OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

SELECT a.iid AS IID, a.indate AS INDATE, a.loginid AS LOGINID, a.factory AS FACTORY, a.storage AS STORAGE, c.subname_ch AS CAR, a.itemcode AS ITEMCODE, b.itemname AS ITEMNAME, a.qty AS QTY, a.barcode AS BARCODE, a.roomcode AS ROOMCODE, a.wccode AS WCCODE, a.ymdhms AS YMDHMS, a.intf_yn AS INTF_YN, a.WMS_KEY AS WMS_KEY, SUBSTR(a.ymdhms, 9, 2) || ':' || SUBSTR(a.ymdhms, 11, 2) AS HHMM,
/* 전체 개수 - 모든 행에 반복 */ (SELECT COUNT(*) FROM t_wms_workmove a2 LEFT JOIN t_mi_item b2 ON b2.itemcode = a2.itemcode LEFT JOIN t_mi_typesub c2 ON c2.subcode = b2.carno AND c2.typecode = 'MI041' WHERE a2.useyn = 'Y' AND a2.source = 'WIPINPUT'
) AS TOTALCOUNT,
/* 총 수량 - 모든 행에 반복 */ (SELECT NVL(SUM(a2.qty), 0) FROM t_wms_workmove a2 LEFT JOIN t_mi_item b2 ON b2.itemcode = a2.itemcode LEFT JOIN t_mi_typesub c2 ON c2.subcode = b2.carno AND c2.typecode = 'MI041' WHERE a2.useyn = 'Y' AND a2.source = 'WIPINPUT'
) AS TOTALQTY
FROM t_wms_workmove a LEFT OUTER JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT OUTER JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' WHERE a.useyn = 'Y' AND a.source = 'WIPINPUT'
ORDER BY a.indate DESC, a.ymdhms DESC, a.barcode

SELECT a.indate AS INDATE, a.factory AS FACTORY, a.storage AS STORAGE, c.subname_ch AS CAR, a.itemcode AS ITEMCODE, b.itemname AS ITEMNAME, SUM(a.qty) AS QTY, a.intf_yn AS INTF_YN, a.wccode AS WCCODE,
/* 전체 개수 - 모든 행에 반복 */ (SELECT COUNT(DISTINCT a2.indate || '_' || a2.itemcode || '_' || a2.wccode) FROM t_wms_workmove a2 LEFT JOIN t_mi_item b2 ON b2.itemcode = a2.itemcode LEFT JOIN t_mi_typesub c2 ON c2.subcode = b2.carno AND c2.typecode = 'MI041' WHERE a2.useyn = 'Y' AND a2.source = 'WIPINPUT'
) AS TOTALCOUNT,
/* 총 수량 - 모든 행에 반복 */ (SELECT NVL(SUM(a2.qty), 0) FROM t_wms_workmove a2 LEFT JOIN t_mi_item b2 ON b2.itemcode = a2.itemcode LEFT JOIN t_mi_typesub c2 ON c2.subcode = b2.carno AND c2.typecode = 'MI041' WHERE a2.useyn = 'Y' AND a2.source = 'WIPINPUT'
) AS TOTALQTY
FROM t_wms_workmove a LEFT OUTER JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT OUTER JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' WHERE a.useyn = 'Y' AND a.source = 'WIPINPUT'
GROUP BY a.indate, a.factory, a.storage, c.subname_ch, a.itemcode, b.itemname, a.intf_yn, a.wccode ORDER BY a.indate DESC, a.itemcode, a.intf_yn

WITH scan_agg AS ( SELECT unpackbarcode, SUM(CASE WHEN useyn = 'Y' THEN qty ELSE 0 END) AS scanqty FROM t_scm_barcode GROUP BY unpackbarcode ), workmove_by_unpack AS ( SELECT sc.unpackbarcode, SUM(wm.qty) AS workmoveqty FROM t_scm_barcode sc JOIN t_wms_workmove wm ON wm.barcode = sc.barcode GROUP BY sc.unpackbarcode ), location_by_unpack AS ( SELECT sc.unpackbarcode, SUM(loc.qty) AS locationqty FROM t_scm_barcode sc JOIN t_wms_location loc ON loc.barcode = sc.barcode GROUP BY sc.unpackbarcode ) SELECT a.sdate AS SDATE, a.factory AS FACTORY, a.storage AS STORAGE, c.subname_ch AS CAR, a.itemcode AS ITEMCODE, b.itemname AS ITEMNAME,
/* 언팩 수량 합 */ SUM(a.qty) AS QTY,
/* PRINT_QTY는 한 그룹 내에서 동일하면 MAX/SUM 아무거나 가능 */ MAX(a.print_qty) AS PRINT_QTY,
/* 스캔수량: 언팩 기준 집계 결과 합 */ NVL(SUM(NVL(sa.scanqty, 0)), 0) AS SCANQTY,
/* 남은 수량 = 언팩합 - 스캔합 */ SUM(a.qty) - NVL(SUM(NVL(sa.scanqty, 0)), 0) AS REMAINING_QTY,
/* WORKMOVE / LOCATION 도 언팩 기준 집계 결과 합 */ NVL(SUM(NVL(wu.workmoveqty, 0)), 0) AS WORKMOVEQTY, NVL(SUM(NVL(lu.locationqty, 0)), 0) AS LOCATIONQTY,
/* 전체 건수 */ ( SELECT COUNT(DISTINCT a2.sdate || '_' || a2.itemcode || '_' || a2.barcode) FROM t_wms_unpack a2 LEFT JOIN t_mi_item b2 ON b2.itemcode = a2.itemcode LEFT JOIN t_mi_typesub c2 ON c2.subcode = b2.carno AND c2.typecode = 'MI041' WHERE a2.useyn = 'Y'
) AS TOTALCOUNT,
/* 전체 수량 */ ( SELECT NVL(SUM(a2.qty), 0) FROM t_wms_unpack a2 LEFT JOIN t_mi_item b2 ON b2.itemcode = a2.itemcode LEFT JOIN t_mi_typesub c2 ON c2.subcode = b2.carno AND c2.typecode = 'MI041' WHERE a2.useyn = 'Y'
) AS TOTALQTY
FROM t_wms_unpack a LEFT JOIN t_mi_item b ON b.itemcode = a.itemcode LEFT JOIN t_mi_typesub c ON c.subcode = b.carno AND c.typecode = 'MI041' LEFT JOIN scan_agg sa ON sa.unpackbarcode = a.barcode LEFT JOIN workmove_by_unpack wu ON wu.unpackbarcode = a.barcode LEFT JOIN location_by_unpack lu ON lu.unpackbarcode = a.barcode
WHERE 1 = 1 AND a.useyn = 'Y'
GROUP BY a.sdate, a.factory, a.storage, c.subname_ch, a.itemcode, b.itemname
ORDER BY a.sdate DESC, a.itemcode

