UPDATE  T_WMS_REALSTOCK set useyn = 'N',
ymdhms_d = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'),
memo_d = 'WMS DELETE'
 WHERE SDATE   = #{date}
   AND FACTORY = #{factory}
   AND STORAGE = #{storage}
   AND USEYN = 'Y'

mapper.select:
SELECT COUNT(*) FROM T_ST_CHANGESUB
 WHERE CONDATE = #{sdate}
   AND ROOMCODE = #{roomcode}

SELECT x.factory, x.storage, x.indate, x.wccode, x.location, x.car, x.itemcode, x.itemname, -- 🔹 그룹별 수량 합계 SUM(x.qty) AS qty, -- 🔹 전체(모든 그룹) 수량 총합 SUM(SUM(x.qty)) OVER () AS totalqty FROM ( SELECT CASE WHEN s.barcode IS NULL THEN '' ELSE a.factory END AS factory, CASE WHEN s.barcode IS NULL THEN '' ELSE a.storage END AS storage, a.wccode AS wccode, REGEXP_SUBSTR(a.wccode, '[0-9]+-[0-9]+-[0-9]+$') AS location, a.indate,
c.subname_ch AS car, a.itemcode AS itemcode, b.itemname AS itemname, a.qty AS qty, a.barcode AS barcode, a.source AS source FROM t_wms_workmove a LEFT JOIN t_wms_workmove s ON s.barcode = a.barcode AND s.source = 'WIPSENDING' AND s.useyn = 'Y' LEFT JOIN t_mi_item b ON b.itemcode = a.itemcode and b.deldate = ' ' LEFT JOIN t_mi_typesub c ON c.subcode = b.carno AND c.typecode = 'MI041' WHERE a.source = 'WIPINPUT' AND a.useyn = 'Y'
) x GROUP BY x.factory, x.storage, x.indate, x.wccode, x.location, x.car, x.itemcode, x.itemname ORDER BY x.indate DESC, x.wccode, x.itemcode

