UPDATE T_WMS_CONSIGNEE
   SET USEYN = 'N'
 WHERE IID = #{id}

UPDATE T_WMS_CONSIGNEE
   SET CONSIGNEE = #{consignee}
     , cinfo1 = #{cinfo1}
     , cinfo2 = #{cinfo2}
     , cinfo3 = #{cinfo3}
     , cinfo4 = #{cinfo4}
     , cinfo5 = #{cinfo5}
     , dinfo1 = #{dinfo1}
     , dinfo2 = #{dinfo2}
     , dinfo3 = #{dinfo3}
     , dinfo4 = #{dinfo4}
     , dinfo5 = #{dinfo5}
WHERE IID = #{id}

choose.when:
SELECT * FROM ( SELECT Z.*, COUNT(*) OVER() AS totalCount, NVL(SUM(NVL(Z.QTY,0)) OVER(),0) AS totalQty, ROW_NUMBER() OVER(
) AS RN2 FROM ( SELECT FACTORY , STORAGE , CAR , ITEMCODE , ITEMNAME , SPEC , SUM(QTY) AS QTY FROM ( SELECT a.FACTORY , a.STORAGE , C.SUBNAME_CH AS CAR , a.ITEMCODE , B.ITEMNAME , b.SPEC AS SPEC --, a.YYYYMM , SUM(a.QTY) AS QTY FROM T_WMS_LOCATION a LEFT JOIN T_MI_ITEM b ON b.ITEMCODE = a.ITEMCODE and b.deldate = ' ' LEFT JOIN t_mi_typesub c ON c.subcode = b.carno WHERE 1 = 1 AND USEYN = 'Y'
GROUP BY a.FACTORY , a.STORAGE , C.SUBNAME_CH , a.ITEMCODE , B.ITEMNAME , b.SPEC --, a.YYYYMM ) GROUP BY FACTORY , STORAGE , CAR , ITEMCODE , ITEMNAME , SPEC ) Z ) WHERE RN2 BETWEEN #{offset} + 1 AND #{offset} + #{itemsPerPage} ORDER BY RN2
